const input = $input.first().json;
const payload = input.payload ?? input;
const text = String(payload.message ?? '').toLowerCase();
const sensitive = ['cancelar', 'contrato', 'cobranca', 'pagamento', 'senha', 'token', 'excluir', 'apagar', 'juridico'].some((word) => text.includes(word));
if (sensitive) {
  return [{ json: { event_id: payload.event_id, status: 'success', action: 'handoff', recipient_phone: payload.sender_phone, message: 'Recebi sua mensagem e vou acionar a equipe da academia para te responder com seguranca.', risk: 'medium', approval_required: false, metadata: { audience: 'external', handoff_required: true } } }];
}
return [{ json: { event_id: payload.event_id, status: 'success', action: 'send_reply', recipient_phone: payload.sender_phone, message: 'Recebi sua mensagem. Posso te ajudar com informacoes gerais por aqui; para dados da sua conta, a equipe assume.', risk: 'low', approval_required: false, metadata: { audience: 'external', same_recipient_only: true } } }];
